// Build a deterministic event key. Same source + event_id must always
// produce the same key, or repeated runs will duplicate records.
function fnv1a(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

const normalize = (v) => String(v).trim().toLowerCase();

const results = [];
for (const item of $input.all()) {
  const data = item.json || {};
  if (!data.source || !data.event_id) {
    throw new Error(
      'Idempotency check rejected: source and event_id are both required. ' +
        'Use stable values, e.g. source="stripe-invoice-sync", event_id="in_1ABC".'
    );
  }
  const composite = normalize(data.source) + '::' + normalize(data.event_id);
  results.push({
    json: {
      event_key: ('evt-' + fnv1a(composite) + '-' + composite).slice(0, 180),
      source: normalize(data.source),
      event_id: String(data.event_id).trim(),
    },
  });
}
return results;

// Duplicate: report it. The caller decides to skip.
const key = $('Validate And Build Key').item.json;
const existing = $input.first().json || {};
return [
  {
    json: {
      duplicate: true,
      event_key: key.event_key,
      source: key.source,
      event_id: key.event_id,
      first_seen_at: existing.first_seen_at || '',
    },
  },
];

// First time we see this event.
return $input.all().map((item) => ({
  json: {
    duplicate: false,
    event_key: item.json.event_key,
    source: item.json.source,
    event_id: item.json.event_id,
    first_seen_at: item.json.first_seen_at,
  },
}));
